        if (!is_null($Action) && !in_array($Action, $allowedValues, true)) {
            throw new \InvalidArgumentException(
                sprintf(
                    "Invalid value for 'Action', must be one of '%s'",
                    implode("', '", $allowedValues)
                )
            );
